curl -sL "https://raw.githubusercontent.com/ksimback/hermes-ecosystem/main/repos/repos.json" 2>/dev/null | python3 -c "
import json, sys
data = json.load(sys.stdin)
print(f'Total repos in atlas: {len(data)}')
# Group by category
cats = {}
for r in data:
    cat = r.get('category','uncategorized')
    cats.setdefault(cat, []).append(r)
for cat, repos in sorted(cats.items()):
    print(f'  {cat}: {len(repos)} repos')
    for r in sorted(repos, key=lambda x: -x.get('stars',0))[:3]:
        print(f'    [{r[\"stars\"]:>6}★] {r[\"name\"]:45s} {r.get(\"description\",\"\")[:80]}')
